    ('pcm-motivation-118', 'Learning and Understanding', 'Reading creates familiarity; solving creates capability. Numeric problems clear your concepts', 117),
    ('pcm-motivation-119', 'Learning and Understanding', 'A doubt asked today can prevent ten errors tomorrow. Assumptions make you pay repeatedly', 118),
