    ('pcm-motivation-128', 'Learning and Understanding', 'Questions strengthen memory more effectively than repeated passive reading.', 127),
    ('pcm-motivation-129', 'Learning and Understanding', 'If a chapter feels overwhelming, begin with its vocabulary and basic relationships.', 128),
    ('pcm-motivation-130', 'Learning and Understanding', 'Deep understanding reduces both revision time and exam anxiety.', 129),
    ('pcm-motivation-131', 'Learning and Understanding', 'The goal is not to remember the page; it is to reconstruct the idea.', 130),
    ('pcm-motivation-132', 'Speed, Accuracy and Stamina', 'Speed without accuracy creates more work, not more marks.', 131),
